Rules.InvariantScript:
If(
    IsBlankOrError(locModeDefault),
    UpdateContext(
        {
            locModeDefault: true,
            locModeWindow: false,
            locModeElevation: false,
            locShowTypes: false,
            locShowReview: false,
            locShowDelete: false,
            locShowPhotos: true,
            locPhotoRecord: Blank(),
            locPhotoFullScreen: false
        }
    );

);
UpdateContext({locAddPhotoLabel: ""});

// reset screen
UpdateContext(
    {
        locModeDefault: true,
        locModeWindow: false,
        locModeElevation: false,
        locShowTypes: false,
        locShowReview: false,
        locShowDelete: false,
        locShowPhotos: true,
        locPhotoRecord: Blank(),
        locPhotoFullScreen: false,
        locReturnScreen: App.ActiveScreen
    }
);

UpdateContext({locBlockUserInput: true});
With(
    {
        varType: "colCdsJobPhotos",
        varRecordRef: locPhotoRecord.'Job Photo'
    },
    If(
        varRecordRef in Filter(
            colAUDRecords,
            Type = "colCdsJobPhotos"
        ).RecordRef,
        // if photo was created on local device
        Remove(
            colCdsJobPhotos,
            LookUp(
                colCdsJobPhotos,
                'Job Photo' = varRecordRef
            )
        );
        Remove(
            colAUDRecords,
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef = varRecordRef
                And Operation = "A"
            )
        ),
        // if photo was downloaded from the server
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "D"
            }
        );
        UpdateIf(
            colCdsJobPhotos,
            'Job Photo' in Filter(
                colAUDRecords,
                Type = varType,
                Operation = "D").RecordRef,
            {
                Status: gblOptionSets.JobPhoto.Status.Inactive,
                'Status Reason': gblOptionSets.JobPhoto.StatusReason.Inactive
            }
        )
    )
);
// save local data
If(
    gblAppLoadOffline,
    SaveData(
        colCdsJobPhotos,
        "localCdsJobPhotos"
    );
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
);
UpdateContext(
    {
        locShowDelete: false,
        locShowReview: false,
        locBlockUserInput: false
    }
)

If(
    locModeDefault,
    UpdateContext(
        {
            locShowTypes: true,
            locShowPhotos: false
        }
    ),
    locModeElevation,
    UpdateContext(
        {
            locShowTypes: true,
            locShowPhotos: false,
            locAddPhotoLabel: ""
        }
    )
);

UpdateContext({locBlockUserInput: true});
With(
    {
        varType: "colCdsJobPhotos",
        varRecordRef: GUID()
    },
    If(
        !IsBlankOrError(Self.Media),
        // Set GUID and add to New Records Collection; match collection
        Patch(
            colCdsJobPhotos,
            Defaults(colCdsJobPhotos),
            {
                'Job Photo': varRecordRef,
                Name: Self.FileName,
                Job: gblRecordJobCurrent,
                'Job Entry': gblRecordJobEntryCurrent_,
                'Window Measurement': gblRecordWindowMeasurement_Tech,
                Type: gblOptionSets.Global.PhotoType.Window,
                Notes: "",
                Image: {
                    Name: Self.FileName,
                    Value: Self.Media,
                    Full: Self.Media
                }
            }
        );
        UpdateContext(
            {
                locShowPhotos: true,
                locShowTypes: false
            }
        );
        // add photo to the AUD records collection
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "A"
            }
        );
    )
);
