    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsJobPhotos,
        "localCdsJobPhotos"
    )
);
*/
UpdateContext({locBlockUserInput: false});

UpdateIf(
    colCdsJobPhotos,
    colCdsJobPhotos[@'Job Photo'] = locPhotoRecord.'Job Photo',
    {Notes: Self.Text}
);

UpdateContext({locBlockUserInput: true});
With(
    {
        varType: "colCdsJobPhotos",
        varRecordRef: locPhotoRecord.'Job Photo'
    },
    UpdateIf(
        colCdsJobPhotos,
        colCdsJobPhotos[@'Job Photo'] = varRecordRef,
        {Notes: Self.Text}
    );
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef = varRecordRef
            )
        ),
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    )
);

IfError( // This line of code is added to hide the errors
If(
    gblAppLoadOffline,
    SaveData(
        colCdsJobPhotos,
        "localCdsJobPhotos"
    );
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
)
,Blank())  // This line of code is added to hide the errors

;
UpdateContext({locBlockUserInput: false});

If(
    gblRecordJobCurrent.Completed = 'Completed (Jobs)'.Yes,
    Back() // <---- fix this
);
UpdateContext({locShowReview: false});
Reset(txt_Photos_Focus_Notes);

Reset(txt_Photos_Focus_Notes);
UpdateContext(
    {
        locShowReview: true,
        locPhotoRecord: ThisItem
    }
);

If(
    !IsBlankOrError(Self.Media),
    With(
        {
            varType: "colCdsJobPhotos",
            varRecordRef: GUID()
        },
        Patch(
            colCdsJobPhotos,
            Defaults(colCdsJobPhotos),
            {
                'Job Photo': varRecordRef,
                Name: Self.FileName,
                Job: gblRecordJobCurrent,
                'Job Entry': gblRecordJobEntryCurrent_,
                Type: ThisItem.Value,
                Notes: "",
                Image: {
                    Name: Self.FileName,
                    Value: Self.Media,
                    Full: Self.Media
                }
            }
        );
        UpdateContext(
            {
                locShowPhotos: true,
                locShowTypes: false
            }
        );
        // add photo to the AUD records collection
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "A"
            }
        );
    )
);
